			string st; cin >> st;

			int a = st.find(':');

			string parent = st.substr(0, a);

			if (!i)start = parent;

			vector<string>children;

			int from = a+1;

			while (1) {

				int r = st.find(',',from);

				if (r == string::npos) {

					children.push_back(st.substr(from,st.find('.')-from));

