            }

            else {

                int u, v; cin >> u >> v;

                u--; v--;

                if(qf.same(u, v)) {

                    cout << qf.query(u, v) << endl;

                }

                else {

                    cout << "UNKNOWN" << endl;

                }

            }

        }

    }

    return 0;

}

